+import java.util.Objects;
+import spoon.Launcher;
+import spoon.reflect.CtModel;
+import spoon.reflect.declaration.CtPackage;
+import spoon.reflect.reference.CtPackageReference;
+import spoon.reflect.reference.CtReference;
+import spoon.reflect.reference.CtTypeReference;
+import spoon.reflect.visitor.filter.TypeFilter;
+
 public class Main {
+
+    private static final String OLD_PREFIX = "javax.mvc";
+    private static final String NEW_PREFIX = "jakarta.mvc";
+
     public static void main(String[] args) {
-        System.out.println("Hello, World!");
+        if (args.length < 1) {
+            throw new IllegalArgumentException("Usage: Main <input-source-dir> [output-source-dir]");
+        }
+
+        Launcher launcher = new Launcher();
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+        launcher.addInputResource(args[0]);
+        launcher.buildModel();
+
+        transform(launcher.getModel());
+
+        if (args.length > 1) {
+            launcher.setSourceOutputDirectory(args[1]);
+            launcher.prettyprint();
+        }
     }
+
+    static void transform(CtModel model) {
+        model.getElements(new TypeFilter<>(CtReference.class)).forEach(Main::rewriteReference);
+        model.getElements(new TypeFilter<>(CtPackage.class)).forEach(Main::rewritePackage);
+    }
+
+    private static void rewriteReference(CtReference reference) {
+        String qualifiedName = reference.getQualifiedName();
+        if (qualifiedName == null || !qualifiedName.equals(OLD_PREFIX) && !qualifiedName.startsWith(OLD_PREFIX + ".")) {
+            return;
+        }
+
+        if (reference instanceof CtTypeReference<?> typeReference) {
+            typeReference.setPackage(typeReference.getFactory().createPackageReference(toJakarta(qualifiedName)));
+            return;
+        }
+
+        if (reference instanceof CtPackageReference packageReference) {
+            packageReference.setSimpleName("jakarta");
+            packageReference.setPackage(packageReference.getFactory().createPackageReference(""));
+            return;
+        }
+
+        reference.setSimpleName(reference.getSimpleName().replaceFirst("^javax", "jakarta"));
+    }
+
+    private static void rewritePackage(CtPackage ctPackage) {
+        String qualifiedName = ctPackage.getQualifiedName();
+        if (qualifiedName == null || !qualifiedName.equals(OLD_PREFIX) && !qualifiedName.startsWith(OLD_PREFIX + ".")) {
+            return;
+        }
+
+        String target = toJakarta(qualifiedName);
+        if (!Objects.equals(qualifiedName, target)) {
+            ctPackage.setSimpleName(target.substring(target.lastIndexOf('.') + 1));
+        }
+    }
+
+    private static String toJakarta(String qualifiedName) {
+        return qualifiedName.equals(OLD_PREFIX) ? NEW_PREFIX : qualifiedName.replaceFirst("^javax\\.mvc", NEW_PREFIX);
+    }
 }
